x_snc_airop_check_definition.check_script:
(function() {
    try {
        if (!gs.tableExists("sn_si_trigger")) {
            return { status: "needs_validation", actualValue: "Table not found", finding: "sn_si_trigger table not present -- manual verification required. Confirm Runbook Automation is installed and active." };
        }
        var gr = new GlideRecord("sn_si_trigger");
        gr.addQuery("active", true);
        gr.query();
        var n = gr.getRowCount();
        if (n >= 10) {
            return { status: "ready", actualValue: n + " active runbook triggers", finding: n + " active runbook triggers -- Now Assist TSOM AI Agents can execute automated remediation." };
        } else {
            return { status: "needs_attention", actualValue: n + " active runbook triggers", finding: "Only " + n + " active runbook triggers. Now Assist TSOM AI Agents use runbook routing rules for automated remediation -- low count limits AI action scope." };
        }
    } catch(e) {
        return { status: "needs_validation", actualValue: "Check failed", finding: "Script execution error: " + e.message };
    }
})
